"use client";

import * as React from "react";
import {
  type ColumnDef,
  type RowSelectionState,
  type SortingState,
  type VisibilityState,
  flexRender,
  getCoreRowModel,
  getSortedRowModel,
  useReactTable,
} from "@tanstack/react-table";

import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";

import {
  DataTablePagination,
  type DataTablePaginationLabels,
} from "./data-table-pagination";
import {
  DataTableServerToolbar,
  type DataTableFilterOptions,
  type DataTableServerToolbarLabels,
} from "./data-table-server-toolbar";

export type DataTableSortDirection = "asc" | "desc";

export interface DataTableFilter {
  columnId?: string;
  label: string;
  allLabel?: string;
  options: { label: string; value: string }[];
  multi?: boolean;
}

export interface DataTableServerLabels {
  loading: string;
  empty: string;
  toolbar: Partial<DataTableServerToolbarLabels>;
  pagination: Partial<DataTablePaginationLabels>;
}

const DEFAULT_LABELS: DataTableServerLabels = {
  loading: "Loading...",
  empty: "No results.",
  toolbar: {},
  pagination: {},
};

export interface DataTableServerProps<TData, TValue, TFilter extends string = string> {
  columns: ColumnDef<TData, TValue>[];
  data: TData[];
  loading?: boolean;
  addButton?: React.ReactNode;
  rowCount: number;
  page: number;
  pageSize: number;
  onPageChange: (page: number) => void;
  onPageSizeChange: (pageSize: number) => void;
  visibility?: VisibilityState;
  sortBy?: string;
  sortDir?: DataTableSortDirection;
  onSortChange?: (sortBy?: string, sortDir?: DataTableSortDirection) => void;
  q?: string;
  onSearchChange?: (q: string) => void;
  f?: TFilter | "";
  onFilterChange?: (f: TFilter | "") => void;
  filterOptions?: DataTableFilterOptions;
  pageSizeOptions?: number[];
  labels?: Partial<DataTableServerLabels>;
}

export function DataTableServer<TData, TValue, TFilter extends string = string>({
  columns,
  data,
  visibility = {},
  loading = false,
  addButton,
  rowCount,
  page,
  pageSize,
  onPageChange,
  onPageSizeChange,
  sortBy,
  sortDir,
  onSortChange,
  q,
  onSearchChange,
  f,
  onFilterChange,
  filterOptions,
  pageSizeOptions,
  labels,
}: DataTableServerProps<TData, TValue, TFilter>) {
  const t = { ...DEFAULT_LABELS, ...labels };
  const [rowSelection, setRowSelection] = React.useState<RowSelectionState>({});
  const [columnVisibility, setColumnVisibility] =
    React.useState<VisibilityState>(visibility);

  const sortingState: SortingState = React.useMemo(
    () => (sortBy && sortDir ? [{ id: sortBy, desc: sortDir === "desc" }] : []),
    [sortBy, sortDir],
  );
  const pageIndex = Math.max(0, page - 1);
  const pageCount = Math.max(1, Math.ceil(rowCount / Math.max(1, pageSize)));
  const paginationState = React.useMemo(
    () => ({ pageIndex, pageSize }),
    [pageIndex, pageSize],
  );

  const table = useReactTable({
    data,
    columns,
    state: {
      sorting: sortingState,
      columnVisibility,
      rowSelection,
      pagination: paginationState,
    },
    manualPagination: true,
    manualSorting: Boolean(onSortChange),
    manualFiltering: Boolean(onSearchChange || onFilterChange),
    pageCount,
    getCoreRowModel: getCoreRowModel(),
    getSortedRowModel: getSortedRowModel(),
    autoResetPageIndex: false,
    autoResetExpanded: false,
    onPaginationChange: (updater) => {
      const next = typeof updater === "function" ? updater(paginationState) : updater;
      if (next.pageIndex !== paginationState.pageIndex) {
        onPageChange(next.pageIndex + 1);
      }
      if (next.pageSize !== paginationState.pageSize) {
        onPageSizeChange(next.pageSize);
      }
    },
    onSortingChange: (updater) => {
      if (!onSortChange) return;
      const next = typeof updater === "function" ? updater(sortingState) : updater;
      const first = next[0];
      onSortChange(first?.id, first ? (first.desc ? "desc" : "asc") : undefined);
    },
    onColumnVisibilityChange: setColumnVisibility,
    onRowSelectionChange: setRowSelection,
  });

  return (
    <div className="space-y-4">
      <DataTableServerToolbar
        table={table}
        addButton={addButton}
        q={q}
        onSearchChange={onSearchChange}
        f={f}
        onFilterChange={onFilterChange}
        filterOptions={filterOptions}
        labels={t.toolbar}
      />
      <DataTablePagination
        table={table}
        labels={t.pagination}
        pageSizeOptions={pageSizeOptions}
      />
      <div className="overflow-x-auto rounded-md border">
        <Table>
          <TableHeader>
            {table.getHeaderGroups().map((headerGroup) => (
              <TableRow key={headerGroup.id}>
                {headerGroup.headers.map((header) => (
                  <TableHead key={header.id} colSpan={header.colSpan}>
                    {header.isPlaceholder
                      ? null
                      : flexRender(header.column.columnDef.header, header.getContext())}
                  </TableHead>
                ))}
              </TableRow>
            ))}
          </TableHeader>
          <TableBody>
            {loading ? (
              <TableRow>
                <TableCell colSpan={columns.length} className="h-24 text-center">
                  {t.loading}
                </TableCell>
              </TableRow>
            ) : table.getRowModel().rows.length ? (
              table.getRowModel().rows.map((row) => (
                <TableRow key={row.id} data-state={row.getIsSelected() && "selected"}>
                  {row.getVisibleCells().map((cell) => (
                    <TableCell key={cell.id}>
                      {flexRender(cell.column.columnDef.cell, cell.getContext())}
                    </TableCell>
                  ))}
                </TableRow>
              ))
            ) : (
              <TableRow>
                <TableCell colSpan={columns.length} className="h-24 text-center">
                  {t.empty}
                </TableCell>
              </TableRow>
            )}
          </TableBody>
        </Table>
      </div>
      <DataTablePagination
        table={table}
        labels={t.pagination}
        pageSizeOptions={pageSizeOptions}
      />
    </div>
  );
}

export const DataTable = DataTableServer;
export type { DataTableFilterOptions };

"use client";

import type * as React from "react";
import type { Column } from "@tanstack/react-table";
import { ArrowDown, ArrowUp, ChevronsUpDown, EyeOff } from "lucide-react";

import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";

export interface DataTableColumnHeaderLabels {
  ascOrder: string;
  descOrder: string;
  hideColumn: string;
}

const DEFAULT_LABELS: DataTableColumnHeaderLabels = {
  ascOrder: "Ascending",
  descOrder: "Descending",
  hideColumn: "Hide column",
};

interface DataTableColumnHeaderProps<TData, TValue>
  extends React.HTMLAttributes<HTMLDivElement> {
  column: Column<TData, TValue>;
  title: string;
  labels?: Partial<DataTableColumnHeaderLabels>;
}

export function DataTableColumnHeader<TData, TValue>({
  column,
  title,
  className,
  labels,
}: DataTableColumnHeaderProps<TData, TValue>) {
  const t = { ...DEFAULT_LABELS, ...labels };
  if (!column.getCanSort()) {
    return <div className={cn(className)}>{title}</div>;
  }

  return (
    <div className={cn("flex items-center space-x-2", className)}>
      <DropdownMenu>
        <DropdownMenuTrigger asChild>
          <Button
            variant="ghost"
            size="sm"
            className="-ml-3 h-8 data-[state=open]:bg-accent"
          >
            <span>{title}</span>
            {column.getIsSorted() === "desc" ? (
              <ArrowDown className="ml-2 size-4" />
            ) : column.getIsSorted() === "asc" ? (
              <ArrowUp className="ml-2 size-4" />
            ) : (
              <ChevronsUpDown className="ml-2 size-4" />
            )}
          </Button>
        </DropdownMenuTrigger>
        <DropdownMenuContent align="start">
          <DropdownMenuItem onClick={() => column.toggleSorting(false)}>
            <ArrowUp className="mr-2 size-3.5 text-muted-foreground/70" />
            {t.ascOrder}
          </DropdownMenuItem>
          <DropdownMenuItem onClick={() => column.toggleSorting(true)}>
            <ArrowDown className="mr-2 size-3.5 text-muted-foreground/70" />
            {t.descOrder}
          </DropdownMenuItem>
          <DropdownMenuSeparator />
          <DropdownMenuItem onClick={() => column.toggleVisibility(false)}>
            <EyeOff className="mr-2 size-3.5 text-muted-foreground/70" />
            {t.hideColumn}
          </DropdownMenuItem>
        </DropdownMenuContent>
      </DropdownMenu>
    </div>
  );
}

"use client";

import type { Table } from "@tanstack/react-table";
import { ChevronLeft, ChevronRight, ChevronsLeft, ChevronsRight } from "lucide-react";

import { Button } from "@/components/ui/button";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";

export interface DataTablePaginationLabels {
  selectedRows: (selected: number, total: number) => string;
  rowsPerPage: string;
  currentPage: (current: number, total: number) => string;
  goToFirstPage: string;
  goToPreviousPage: string;
  goToNextPage: string;
  goToLastPage: string;
}

const DEFAULT_LABELS: DataTablePaginationLabels = {
  selectedRows: (selected, total) => `${selected} of ${total} selected`,
  rowsPerPage: "Rows per page",
  currentPage: (current, total) => `Page ${current} of ${total}`,
  goToFirstPage: "Go to first page",
  goToPreviousPage: "Go to previous page",
  goToNextPage: "Go to next page",
  goToLastPage: "Go to last page",
};

interface DataTablePaginationProps<TData> {
  table: Table<TData>;
  labels?: Partial<DataTablePaginationLabels>;
  pageSizeOptions?: number[];
}

export function DataTablePagination<TData>({
  table,
  labels,
  pageSizeOptions = [10, 20, 30, 40, 50],
}: DataTablePaginationProps<TData>) {
  const t = { ...DEFAULT_LABELS, ...labels };
  return (
    <div className="flex flex-col gap-3 px-2 sm:flex-row sm:items-center sm:justify-between">
      <div className="flex-1 text-sm text-muted-foreground">
        {t.selectedRows(
          table.getFilteredSelectedRowModel().rows.length,
          table.getFilteredRowModel().rows.length,
        )}
      </div>
      <div className="flex flex-wrap items-center gap-4 sm:gap-6 lg:gap-8">
        <div className="flex items-center space-x-2">
          <p className="text-sm font-medium">{t.rowsPerPage}</p>
          <Select
            value={`${table.getState().pagination.pageSize}`}
            onValueChange={(value) => table.setPageSize(Number(value))}
          >
            <SelectTrigger className="h-8 w-[70px]">
              <SelectValue placeholder={table.getState().pagination.pageSize} />
            </SelectTrigger>
            <SelectContent side="top">
              {pageSizeOptions.map((pageSize) => (
                <SelectItem key={pageSize} value={`${pageSize}`}>
                  {pageSize}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
        <div className="flex w-[100px] items-center justify-center text-sm font-medium">
          {t.currentPage(table.getState().pagination.pageIndex + 1, table.getPageCount())}
        </div>
        <div className="flex items-center space-x-2">
          <Button
            variant="outline"
            className="hidden size-8 p-0 lg:flex"
            onClick={() => table.setPageIndex(0)}
            disabled={!table.getCanPreviousPage()}
          >
            <span className="sr-only">{t.goToFirstPage}</span>
            <ChevronsLeft className="size-4" />
          </Button>
          <Button
            variant="outline"
            className="size-8 p-0"
            onClick={() => table.previousPage()}
            disabled={!table.getCanPreviousPage()}
          >
            <span className="sr-only">{t.goToPreviousPage}</span>
            <ChevronLeft className="size-4" />
          </Button>
          <Button
            variant="outline"
            className="size-8 p-0"
            onClick={() => table.nextPage()}
            disabled={!table.getCanNextPage()}
          >
            <span className="sr-only">{t.goToNextPage}</span>
            <ChevronRight className="size-4" />
          </Button>
          <Button
            variant="outline"
            className="hidden size-8 p-0 lg:flex"
            onClick={() => table.setPageIndex(table.getPageCount() - 1)}
            disabled={!table.getCanNextPage()}
          >
            <span className="sr-only">{t.goToLastPage}</span>
            <ChevronsRight className="size-4" />
          </Button>
        </div>
      </div>
    </div>
  );
}

"use client";

import * as React from "react";
import { Check, PlusCircle } from "lucide-react";

import { cn } from "@/lib/utils";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import {
  Command,
  CommandEmpty,
  CommandGroup,
  CommandInput,
  CommandItem,
  CommandList,
  CommandSeparator,
} from "@/components/ui/command";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Separator } from "@/components/ui/separator";

export interface FacetedFilterOption {
  label: string;
  value: string;
  icon?: React.ComponentType<{ className?: string }>;
}

export interface DataTableServerFacetedFilterLabels {
  clear: string;
  empty: string;
  selected: (count: number) => string;
}

const DEFAULT_LABELS: DataTableServerFacetedFilterLabels = {
  clear: "Clear",
  empty: "No results found.",
  selected: (count) => `${count} selected`,
};

interface DataTableServerFacetedFilterProps<TFilter extends string> {
  title: string;
  options: FacetedFilterOption[];
  value: TFilter | "";
  onFilterChange: (value: TFilter | "") => void;
  labels?: Partial<DataTableServerFacetedFilterLabels>;
  multi?: boolean;
}

export function DataTableServerFacetedFilter<TFilter extends string>({
  title,
  options,
  value,
  onFilterChange,
  labels,
  multi = true,
}: DataTableServerFacetedFilterProps<TFilter>) {
  const t = { ...DEFAULT_LABELS, ...labels };
  const selected = React.useMemo<Set<string>>(() => {
    if (!value) return new Set<string>();
    return multi ? new Set(String(value).split(",").filter(Boolean)) : new Set([String(value)]);
  }, [multi, value]);

  const selectedCount = selected.size;

  const toggleMulti = (nextValue: string) => {
    const next = new Set(selected);
    if (next.has(nextValue)) {
      next.delete(nextValue);
    } else {
      next.add(nextValue);
    }
    onFilterChange((Array.from(next).join(",") as TFilter) || "");
  };

  const chooseSingle = (nextValue: string) => {
    const current = selected.values().next().value as string | undefined;
    onFilterChange(current === nextValue ? "" : (nextValue as TFilter));
  };

  return (
    <Popover>
      <PopoverTrigger asChild>
        <Button variant="outline" size="sm" className="h-8 border-dashed">
          <PlusCircle className="mr-2 size-4" />
          {title}
          {selectedCount > 0 ? (
            <>
              <Separator orientation="vertical" className="mx-2 h-4" />
              <Badge variant="secondary" className="rounded-sm px-1 font-normal lg:hidden">
                {selectedCount}
              </Badge>
              <div className="hidden space-x-1 lg:flex">
                {selectedCount > 2 ? (
                  <Badge variant="secondary" className="rounded-sm px-1 font-normal">
                    {t.selected(selectedCount)}
                  </Badge>
                ) : (
                  options
                    .filter((option) => selected.has(option.value))
                    .map((option) => (
                      <Badge
                        key={option.value}
                        variant="secondary"
                        className="rounded-sm px-1 font-normal"
                      >
                        {option.label}
                      </Badge>
                    ))
                )}
              </div>
            </>
          ) : null}
        </Button>
      </PopoverTrigger>
      <PopoverContent className="w-[220px] p-0" align="start">
        <Command>
          <CommandInput placeholder={title} />
          <CommandList>
            <CommandEmpty>{t.empty}</CommandEmpty>
            <CommandGroup>
              {options.map((option) => {
                const isSelected = selected.has(option.value);
                return (
                  <CommandItem
                    key={option.value}
                    onSelect={() => {
                      if (multi) {
                        toggleMulti(option.value);
                      } else {
                        chooseSingle(option.value);
                      }
                    }}
                  >
                    <div
                      className={cn(
                        "mr-2 flex size-4 items-center justify-center rounded-sm border border-primary",
                        isSelected
                          ? "bg-primary text-primary-foreground"
                          : "opacity-50 [&_svg]:invisible",
                      )}
                    >
                      <Check className="size-4" />
                    </div>
                    {option.icon ? (
                      <option.icon className="mr-2 size-4 text-muted-foreground" />
                    ) : null}
                    <span>{option.label}</span>
                  </CommandItem>
                );
              })}
            </CommandGroup>
            {selectedCount > 0 ? (
              <>
                <CommandSeparator />
                <CommandGroup>
                  <CommandItem onSelect={() => onFilterChange("")} className="justify-center">
                    {t.clear}
                  </CommandItem>
                </CommandGroup>
              </>
            ) : null}
          </CommandList>
        </Command>
      </PopoverContent>
    </Popover>
  );
}

"use client";

import * as React from "react";
import type { Table } from "@tanstack/react-table";
import { Search, X } from "lucide-react";

import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";

import {
  DataTableServerFacetedFilter,
  type DataTableServerFacetedFilterLabels,
  type FacetedFilterOption,
} from "./data-table-server-faceted-filter";
import {
  DataTableViewOptions,
  type DataTableViewOptionsLabels,
} from "./data-table-view-options";

export interface DataTableFilterOptions {
  title: string;
  options: FacetedFilterOption[];
  multi?: boolean;
}

export interface DataTableServerToolbarLabels {
  search: string;
  reset: string;
  viewOptions: Partial<DataTableViewOptionsLabels>;
  facetedFilter: Partial<DataTableServerFacetedFilterLabels>;
}

const DEFAULT_LABELS: DataTableServerToolbarLabels = {
  search: "Search",
  reset: "Reset",
  viewOptions: {},
  facetedFilter: {},
};

interface DataTableServerToolbarProps<TData, TFilter extends string> {
  table: Table<TData>;
  addButton?: React.ReactNode;
  q?: string;
  onSearchChange?: (q: string) => void;
  f?: TFilter | "";
  onFilterChange?: (f: TFilter | "") => void;
  filterOptions?: DataTableFilterOptions;
  labels?: Partial<DataTableServerToolbarLabels>;
}

export function DataTableServerToolbar<TData, TFilter extends string>({
  table,
  addButton,
  q,
  onSearchChange,
  f,
  onFilterChange,
  filterOptions,
  labels,
}: DataTableServerToolbarProps<TData, TFilter>) {
  const t = { ...DEFAULT_LABELS, ...labels };
  const [qSearch, setQSearch] = React.useState(q ?? "");

  React.useEffect(() => {
    setQSearch(q ?? "");
  }, [q]);

  return (
    <div className="flex flex-col gap-2 lg:flex-row lg:items-center lg:justify-between">
      <div className="flex flex-1 flex-wrap items-center gap-2">
        {onSearchChange ? (
          <div className="flex flex-wrap items-center gap-2">
            <Input
              placeholder={t.search}
              value={qSearch}
              onChange={(event) => setQSearch(event.target.value)}
              className="h-8 w-[150px] lg:w-[250px]"
              aria-label={t.search}
            />
            <Button
              variant="ghost"
              className="h-8 px-2 lg:px-3"
              onClick={() => onSearchChange(qSearch)}
            >
              {t.search}
              <Search className="ml-2 size-4" />
            </Button>
            {qSearch ? (
              <Button
                variant="ghost"
                onClick={() => {
                  setQSearch("");
                  onSearchChange("");
                }}
                className="h-8 px-2 lg:px-3"
              >
                {t.reset}
                <X className="ml-2 size-4" />
              </Button>
            ) : null}
          </div>
        ) : null}
        {onFilterChange && filterOptions ? (
          <DataTableServerFacetedFilter
            title={filterOptions.title}
            options={filterOptions.options}
            value={f ?? ""}
            onFilterChange={onFilterChange}
            labels={t.facetedFilter}
            multi={filterOptions.multi}
          />
        ) : null}
      </div>
      <div className="flex items-center gap-2">
        <DataTableViewOptions table={table} labels={t.viewOptions} />
        {addButton}
      </div>
    </div>
  );
}

"use client";

import type { Table } from "@tanstack/react-table";
import { Settings2 } from "lucide-react";

import { Button } from "@/components/ui/button";
import {
  DropdownMenu,
  DropdownMenuCheckboxItem,
  DropdownMenuContent,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";

export interface DataTableViewOptionsLabels {
  view: string;
  toggleColumns: string;
}

const DEFAULT_LABELS: DataTableViewOptionsLabels = {
  view: "View",
  toggleColumns: "Toggle columns",
};

interface DataTableViewOptionsProps<TData> {
  table: Table<TData>;
  labels?: Partial<DataTableViewOptionsLabels>;
}

export function DataTableViewOptions<TData>({
  table,
  labels,
}: DataTableViewOptionsProps<TData>) {
  const t = { ...DEFAULT_LABELS, ...labels };
  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button variant="outline" size="sm" className="ml-auto h-8">
          <Settings2 className="mr-2 size-4" />
          {t.view}
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end" className="w-[170px]">
        <DropdownMenuLabel>{t.toggleColumns}</DropdownMenuLabel>
        <DropdownMenuSeparator />
        {table
          .getAllColumns()
          .filter((column) => typeof column.accessorFn !== "undefined" && column.getCanHide())
          .map((column) => (
            <DropdownMenuCheckboxItem
              key={column.id}
              className="capitalize"
              checked={column.getIsVisible()}
              onCheckedChange={(value) => column.toggleVisibility(Boolean(value))}
            >
              {column.id}
            </DropdownMenuCheckboxItem>
          ))}
      </DropdownMenuContent>
    </DropdownMenu>
  );
}
